random.seed(42)
# Build a treap: insert 1..7
def insert(root, key):
    def merge(a, b):
        if not a: return b
        if not b: return a
        if a.priority > b.priority:
            a.right = merge(a.right, b)
            return a
        else:
            b.left = merge(a, b.left)
            return b
    l, r = split(root, key)
    return merge(merge(l, Node(key)), r)

root = None
for k in [4,2,6,1,3,5,7]:
    root = insert(root, k)

# Split at 4: left should have 1,2,3,4 and right 5,6,7
l, r = split(root, 4)
def collect(node):
    if not node: return []
    return collect(node.left) + [node.key] + collect(node.right)
assert sorted(collect(l)) == [1,2,3,4], f'Left: {sorted(collect(l))}'
assert sorted(collect(r)) == [5,6,7],   f'Right: {sorted(collect(r))}'
# Heap (max-priority) property: every parent priority >= children
def check_heap(node):
    if not node: return True
    if node.left  and node.left.priority  > node.priority: return False
    if node.right and node.right.priority > node.priority: return False
    return check_heap(node.left) and check_heap(node.right)
assert check_heap(l) and check_heap(r)
